package com.google.gson.internal.reflect;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Constructor;
import java.lang.reflect.InvocationTargetException;

import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class ReflectionHelperTest {

  static class TestRecord {
    final int x;
    final String y;

    public TestRecord(int x, String y) {
      this.x = x;
      this.y = y;
    }
  }

  static class NonRecord {
    public NonRecord() {}
  }

  @BeforeAll
  static void setup() {
    // No setup required for this static method test
  }

  @Test
  void getCanonicalRecordConstructor_returnsConstructorForRecord() throws Exception {
    // Since RECORD_HELPER is private static final, we mock the static field via reflection
    RecordHelper mockRecordHelper = mock(RecordHelper.class);
    Constructor<TestRecord> constructor = TestRecord.class.getDeclaredConstructor(int.class, String.class);
    when(mockRecordHelper.getCanonicalRecordConstructor(TestRecord.class)).thenReturn(constructor);

    // Replace the private static final RECORD_HELPER field with mockRecordHelper via reflection
    var recordHelperField = ReflectionHelper.class.getDeclaredField("RECORD_HELPER");
    recordHelperField.setAccessible(true);

    // Remove final modifier using reflection (hack)
    var modifiersField = java.lang.reflect.Field.class.getDeclaredField("modifiers");
    modifiersField.setAccessible(true);
    modifiersField.setInt(recordHelperField, recordHelperField.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

    recordHelperField.set(null, mockRecordHelper);

    Constructor<TestRecord> result = ReflectionHelper.getCanonicalRecordConstructor(TestRecord.class);

    assertNotNull(result);
    assertEquals(constructor, result);

    verify(mockRecordHelper).getCanonicalRecordConstructor(TestRecord.class);
  }

  @Test
  void getCanonicalRecordConstructor_propagatesExceptionFromRecordHelper() throws Exception {
    RecordHelper mockRecordHelper = mock(RecordHelper.class);
    when(mockRecordHelper.getCanonicalRecordConstructor(NonRecord.class))
        .thenThrow(new RuntimeException("Test exception"));

    var recordHelperField = ReflectionHelper.class.getDeclaredField("RECORD_HELPER");
    recordHelperField.setAccessible(true);

    var modifiersField = java.lang.reflect.Field.class.getDeclaredField("modifiers");
    modifiersField.setAccessible(true);
    modifiersField.setInt(recordHelperField, recordHelperField.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

    recordHelperField.set(null, mockRecordHelper);

    RuntimeException thrown = assertThrows(RuntimeException.class, () -> {
      ReflectionHelper.getCanonicalRecordConstructor(NonRecord.class);
    });

    assertEquals("Test exception", thrown.getMessage());
  }
}
